    function drawPdfPageNumber(doc, pageNumber, pageCount) {
      const pageWidth = doc.internal.pageSize.getWidth();
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(71, 85, 105);
      doc.text(`${pageNumber}/${pageCount}`, pageWidth - 14, 12, { align: 'right' });
    }

    function loadImageAsDataUrl(src) {
      if (PDF_LOGO_DATA_URL) return Promise.resolve(PDF_LOGO_DATA_URL);
      return Promise.reject(new Error('Logo data is not available'));
    }

    function drawPdfSignatureBlock(doc, startY, marginX = 8, tableWidth = null) {
      const pageWidth = doc.internal.pageSize.getWidth();
      const availableWidth = tableWidth || (pageWidth - (marginX * 2));
      const boxWidth = availableWidth / 3;
      const boxHeight = 18;
      const labelY = startY + boxHeight - 3;
      const labels = ['Prepared by / Date', 'Checked by / Date', 'Authorize by / Date'];

      doc.setDrawColor(120, 120, 120);
      doc.setLineWidth(0.3);
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(8.5);
      doc.setTextColor(31, 41, 55);

      labels.forEach((label, index) => {
        const x = marginX + (index * boxWidth);
        doc.rect(x, startY, boxWidth, boxHeight);
        doc.text(label, x + (boxWidth / 2), labelY, { align: 'center' });
      });
    }

    async function exportReportPdf() {
      const rows = getPdfExportRows();
      if (!rows.length) {
        await Swal.fire(swalTheme({ icon: 'warning', title: 'No data to export' }));
        return;
      }
      const confirmed = await Swal.fire(swalTheme({
        icon: 'question',
        title: 'Export current table to PDF?',
        showCancelButton: true,
        confirmButtonText: 'Export',
        cancelButtonText: 'Cancel'
      }));
      if (!confirmed.isConfirmed) return;

      Swal.fire(swalTheme({
        title: 'Generating PDF...',
        showCloseButton: false,
        allowOutsideClick: false,
        allowEscapeKey: false,
        didOpen: () => Swal.showLoading()
      }));

      try {
        if (!window.jspdf || !window.jspdf.jsPDF) {
          throw new Error('PDF library is not available');
        }
        const { jsPDF } = window.jspdf;
        const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
        const month = document.getElementById('monthInput')?.value || '';
        const monthText = monthLabel(month) || month;
        const subcon = (currentUser?.subcon || currentUser?.username || 'SUBCON').toUpperCase();
        const fileName = `SubconInventory_${subcon}_${buildTimestampForFileName()}.pdf`;
        const totalRowIndex = rows.length;
        const exportBody = [...rows, getPdfTotalsRow()];
        const tableLeft = 8;
        const tableRight = 8;
        const tableWidth = doc.internal.pageSize.getWidth() - tableLeft - tableRight;
        const logoAspectRatio = 1797 / 237;
        const logoWidth = 26;
        const logoHeight = logoWidth / logoAspectRatio;
        const logoX = tableLeft;
        const logoY = 8.5;
        const headerTextX = tableLeft;

        try {
          const logoDataUrl = await loadImageAsDataUrl('assets/logo.png');
          doc.addImage(logoDataUrl, 'PNG', logoX, logoY, logoWidth, logoHeight);
        } catch (_) {}

        doc.setFont('helvetica', 'bold');
        doc.setFontSize(10);
        doc.setTextColor(71, 85, 105);
        doc.text('Sub-con Inventory Data Check System', headerTextX, 17);
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(16);
        doc.setTextColor(15, 23, 42);
        doc.text(`Monthly Inventory report ${monthText} (${subcon})`, headerTextX, 24);

        doc.autoTable({
          startY: 31,
          margin: { left: tableLeft, right: tableRight },
          tableWidth,
          head: [[
            'Item',
            'File No.',
            'BOH',
            'Supply',
            'Delivery',
            'NG',
            'EOH',
            'Supplier confirm OK',
            'Supplier confirm Hold',
            'Total',
            'Diff',
            'Remark'
          ]],
          body: exportBody,
          theme: 'grid',
          styles: {
            font: 'helvetica',
            fontSize: 6.6,
            cellPadding: 1.4,
            overflow: 'linebreak',
            valign: 'middle'
          },
          headStyles: {
            fillColor: [31, 41, 55],
            textColor: [255, 255, 255],
            fontStyle: 'bold',
            halign: 'center'
          },
          columnStyles: {
            0: { halign: 'center', cellWidth: 9 },
            1: { halign: 'left', cellWidth: 14 },
            2: { halign: 'right', cellWidth: 10 },
            3: { halign: 'right', cellWidth: 11 },
            4: { halign: 'right', cellWidth: 11 },
            5: { halign: 'right', cellWidth: 8 },
            6: { halign: 'right', cellWidth: 10 },
            7: { halign: 'right', cellWidth: 16 },
            8: { halign: 'right', cellWidth: 16 },
            9: { halign: 'right', cellWidth: 10 },
            10: { halign: 'right', cellWidth: 10 },
            11: { halign: 'left', cellWidth: 69 }
          },
          didParseCell: (data) => {
            if (data.section === 'body' && data.row.index === totalRowIndex) {
              data.cell.styles.fillColor = [219, 234, 254];
              data.cell.styles.textColor = [15, 23, 42];
              data.cell.styles.fontStyle = 'bold';
              data.cell.styles.fontSize = 6.1;
              data.cell.styles.cellPadding = 1.1;
              data.cell.styles.overflow = 'visible';
            }
            if (data.section === 'body' && data.column.index === 10) {
              data.cell.styles.textColor = [15, 23, 42];
            }
          }
        });
        const pageHeight = doc.internal.pageSize.getHeight();
        let lastPage = doc.getNumberOfPages();
        doc.setPage(lastPage);
        let signatureY = (doc.lastAutoTable?.finalY || 24) + 10;
        const signatureBlockHeight = 22;
        if (signatureY + signatureBlockHeight > pageHeight - 10) {
          doc.addPage();
          lastPage = doc.getNumberOfPages();
          doc.setPage(lastPage);
          signatureY = 18;
        }
        drawPdfSignatureBlock(doc, signatureY, tableLeft, tableWidth);

        const totalPages = doc.getNumberOfPages();
        for (let page = 1; page <= totalPages; page += 1) {
          doc.setPage(page);
          drawPdfPageNumber(doc, page, totalPages);
        }

        if (Swal.isVisible()) Swal.close();
        doc.save(fileName);
        await new Promise((resolve) => setTimeout(resolve, 120));
        await Swal.fire(swalTheme({ icon: 'success', title: 'PDF exported successfully' }));
      } catch (error) {
        if (Swal.isVisible()) Swal.close();
        await Swal.fire(swalTheme({ icon: 'error', title: 'Export failed', text: error.message }));
      }
    }

    function getEditableCells() {
      return [...document.querySelectorAll('#reportBody input:not([disabled]), #reportBody textarea')];
    }

    function bindExcelKeys() {
      document.getElementById('reportBody').addEventListener('keydown', (e) => {
        if (e.key !== 'Enter') return;
        const target = e.target;
        if (!(target.matches('input') || target.matches('textarea'))) return;
        e.preventDefault();
        const cells = getEditableCells();
        const idx = cells.indexOf(target);
        if (idx < 0) return;
        const next = cells[idx + 1];
        if (next) {
          next.focus();
          if (next.select) next.select();
          return;
        }
        addRow();
        const updated = getEditableCells();
        const firstNew = updated[idx + 1];
        if (firstNew) firstNew.focus();
      });
    }

    async function loadReport(showLoading = true, force = false) {
      const month = document.getElementById('monthInput').value;
      updateMonthlyTitle();
      if (!month) return Swal.fire(swalTheme({ icon: 'warning', title: 'Please select a month' }));
      isLoadingReport = true;
      if (showLoading) {
        await showLoadingSwal('Loading data...');
      }
      try {
        const res = await fetchMonthData(month, force);
        if (showLoading) Swal.close();
        if (!res.ok) return Swal.fire(swalTheme({ icon: 'error', title: res.message || 'Failed to load data' }));
        setEditMode(!!res.allowed, res.deadlineDate || '');
        const dataRows = res.rows || [];
        renderRows(dataRows);
        lastLoadedMonth = month;
        const hasSavedRows = dataRows.some((r) =>
          String(r.fileNo || '').trim() ||
          String(r.boh || '').trim() ||
          String(r.supply || '').trim() ||
          String(r.delivery || '').trim() ||
          String(r.ng || '').trim() ||
          String(r.eoh || '').trim() ||
          String(r.confirmOk || '').trim() ||
          String(r.confirmHold || '').trim() ||
          String(r.remark || '').trim()
        );
        lastUpdatedText = hasSavedRows ? new Date().toLocaleString('en-GB') : '-';
        renderDashboardKpiFromRows(collectRows());
        clearDirty();
      } catch (e) {
        if (showLoading) Swal.close();
        Swal.fire(swalTheme({ icon: 'error', title: 'Failed to load data', text: e.message }));
      } finally {
        isLoadingReport = false;
      }
    }

    async function saveReport() {
      if (!editAllowed) return Swal.fire(swalTheme({ icon: 'warning', title: 'This month is locked by deadline' }));
      const ok = await Swal.fire(swalTheme({ icon: 'question', title: 'Save report data?', showCancelButton: true, confirmButtonText: 'Save', cancelButtonText: 'Cancel' }));
      if (!ok.isConfirmed) return;
      const rows = collectRows();

      Swal.fire(swalTheme({ title: rows.length ? 'Saving data...' : 'Clearing data...', showCloseButton: false, allowOutsideClick: false, allowEscapeKey: false, didOpen: () => Swal.showLoading() }));
      try {
        const res = await api('saveReport', { month: document.getElementById('monthInput').value, subcon: currentUser.subcon, username: currentUser.username, rows });
        Swal.close();
        if (!res.ok) return Swal.fire(swalTheme({ icon: 'error', title: res.message || 'Save failed' }));
        await Swal.fire(swalTheme({ icon: 'success', title: rows.length ? 'Data saved successfully' : 'All data cleared successfully' }));
        clearDirty();
        dashboardTrendCache = {};
        monthDataCache = {};
        lastUpdatedText = rows.length ? new Date().toLocaleString('en-GB') : '-';
        loadReport(true, true);
      } catch (e) {
        Swal.close();
        Swal.fire(swalTheme({ icon: 'error', title: 'Save failed', text: e.message }));
      }
    }

    async function setMenu(menu, options = {}) {
      const showLoading = options.showLoading !== false;
      const force = options.force === true;
      const isDashboard = menu === 'dashboard';
      const isAddData = menu === 'addData';
      if (isDashboard) {
        const ok = await guardUnsavedChanges();
        if (!ok) return;
      }
      document.getElementById('dashboardView').classList.toggle('hidden', !isDashboard);
      document.getElementById('addDataView').classList.toggle('hidden', !isAddData);
      document.getElementById('menuDashboard').classList.toggle('active', isDashboard);
      document.getElementById('menuAddData').classList.toggle('active', isAddData);
      document.getElementById('pageHeader').classList.toggle('hidden', !isDashboard);
      if (isDashboard) {
        renderDashboardSubmissionStatus();
        renderDashboardKpiFromRows(collectRows());
        await loadDashboardPanels(showLoading, force);
      } else if (isAddData) {
        const currentMonth = document.getElementById('monthInput').value || '';
        if (!lastLoadedMonth || lastLoadedMonth !== currentMonth) {
          await loadReport(showLoading, force);
        }
      }
    }

